mapper.update:
UPDATE TZ_MEMBER SET LGCNT = LGCNT + 1,
LGFIRST = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS'),
LGIP = #{lgip}, LGFAIL = 0, LGLAST= TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') WHERE USERID = #{userid}

mapper.select:
SELECT COUNT(*) CNT
FROM TN_TEST_MEMBER A
   , TZ_MEMBER B
WHERE A.TESTID = #{userid}
  AND A.TESTID = B.USERID
  AND B.COMP = #{etcCompCd}

mapper.update:
UPDATE
    TZ_MEMBER
SET PWD = #{s_pwd}
WHERE USERID = #{s_userid}

mapper.select:
SELECT COUNT(*) CNT
FROM TB_FRONT_MENU
WHERE LINK_URL = #{chkUrl}

SELECT PUBLIC_KEY
FROM TB_RSA_LOGIN
WHERE KEY_SEQ = #{encSeq}

SELECT PRIVATE_KEY
FROM TB_RSA_LOGIN
WHERE KEY_SEQ = #{s_encSeq}

SELECT SESSION_ID
FROM TB_USER_SESSION
WHERE USER_ID = #{userid}
